package com.maum.backend.exception

class UserNotFoundException(userId: String) : RuntimeException("사용자를 찾을 수 없습니다: $userId")
class AlreadyFollowingException(followerId: String, followingId: String) :
    RuntimeException("이미 팔로우 중입니다: $followerId -> $followingId")
class SelfFollowException : RuntimeException("자기 자신을 팔로우할 수 없습니다")
class NotFollowingException(followerId: String, followingId: String) :
    RuntimeException("팔로우 관계가 아닙니다: $followerId -> $followingId")
