## 5. 단위 테스트 (핵심)

**파일**: `user/src/test/kotlin/com/maum/backend/service/user/UserServiceTest.kt`

```kotlin
package com.maum.backend.service.user

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.entity.user.UserEntity
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.NotFollowingException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.exception.UserNotFoundException
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.assertj.core.api.Assertions.assertThat
import org.assertj.core.api.Assertions.assertThatThrownBy
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.ArgumentCaptor
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.*
import org.mockito.junit.jupiter.MockitoExtension

@ExtendWith(MockitoExtension::class)
class UserServiceTest {

    @Mock
    private lateinit var userRepository: UserRepository

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // ──────────────────────────────────────────────
    // follow()
    // ──────────────────────────────────────────────

    @Test
    fun `should follow successfully when valid follower and following`() {
        // given
        val followerId = "user-A"
        val followingId = "user-B"

        `when`(userRepository.existsById(followerId)).thenReturn(true)
        `when`(userRepository.existsById(followingId)).thenReturn(true)
        `when`(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(false)

        // when
        userService.follow(followerId, followingId)

        // then
        val captor = ArgumentCaptor.forClass(FollowEntity::class.java)
        verify(followRepository).save(captor.capture())
        assertThat(captor.value.followerId).isEqualTo(followerId)
        assertThat(captor.value.followingId).isEqualTo(followingId)
    }

    @Test
    fun `should throw SelfFollowException when follower and following are same`() {
        // given
        val userId = "user-A"

        // when & then
        assertThatThrownBy { userService.follow(userId, userId) }
            .isInstanceOf(SelfFollowException::class.java)

        verifyNoInteractions(userRepository)
        verifyNoInteractions(followRepository)
    }

    @Test
    fun `should throw UserNotFoundException when follower does not exist`() {
        // given
        val followerId = "non-existent-user"
        val followingId = "user-B"

        `when`(userRepository.existsById(followerId)).thenReturn(false)

        // when & then
        assertThatThrownBy { userService.follow(followerId, followingId) }
            .isInstanceOf(UserNotFoundException::class.java)
            .hasMessageContaining(followerId)

        verify(userRepository).existsById(followerId)
        verify(userRepository, never()).existsById(followingId)
        verifyNoInteractions(followRepository)
    }

    @Test
    fun `should throw UserNotFoundException when following user does not exist`() {
        // given
        val followerId = "user-A"
        val followingId = "non-existent-user"

        `when`(userRepository.existsById(followerId)).thenReturn(true)
        `when`(userRepository.existsById(followingId)).thenReturn(false)

        // when & then
        assertThatThrownBy { userService.follow(followerId, followingId) }
            .isInstanceOf(UserNotFoundException::class.java)
            .hasMessageContaining(followingId)

        verifyNoInteractions(followRepository)
    }

    @Test
    fun `should throw AlreadyFollowingException when already following`() {
        // given
        val followerId = "user-A"
        val followingId = "user-B"

        `when`(userRepository.existsById(followerId)).thenReturn(true)
        `when`(userRepository.existsById(followingId)).thenReturn(true)
        `when`(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(true)

        // when & then
        assertThatThrownBy { userService.follow(followerId, followingId) }
            .isInstanceOf(AlreadyFollowingException::class.java)

        verify(followRepository, never()).save(any())
    }

    // ──────────────────────────────────────────────
    // unfollow()
    // ──────────────────────────────────────────────

    @Test
    fun `should unfollow successfully when follow relationship exists`() {
        // given
        val followerId = "user-A"
        val followingId = "user-B"
        val followEntity = FollowEntity(
            id = "follow-id-1",
            followerId = followerId,
            followingId = followingId,
        )

        `when`(followRepository.findByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(followEntity)

        // when
        userService.unfollow(followerId, followingId)

        // then
        verify(followRepository).delete(followEntity)
    }

    @Test
    fun `should throw SelfFollowException when unfollow self`() {
        // given
        val userId = "user-A"

        // when & then
        assertThatThrownBy { userService.unfollow(userId, userId) }
            .isInstanceOf(SelfFollowException::class.java)

        verifyNoInteractions(followRepository)
    }

    @Test
    fun `should throw NotFollowingException when follow relationship does not exist`() {
        // given
        val followerId = "user-A"
        val followingId = "user-B"

        `when`(followRepository.findByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(null)

        // when & then
        assertThatThrownBy { userService.unfollow(followerId, followingId) }
            .isInstanceOf(NotFollowingException::class.java)

        verify(followRepository, never()).delete(any())
    }

    // ──────────────────────────────────────────────
    // isFollowing()
    // ──────────────────────────────────────────────

    @Test
    fun `should return true when following relationship exists`() {
        // given
        val followerId = "user-A"
        val followingId = "user-B"

        `when`(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(true)

        // when
        val result = userService.isFollowing(followerId, followingId)

        // then
        assertThat(result).isTrue()
        verify(followRepository).existsByFollowerIdAndFollowingId(followerId, followingId)
    }

    @Test
    fun `should return false when following relationship does not exist`() {
        // given
        val followerId = "user-A"
        val followingId = "user-B"

        `when`(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(false)

        // when
        val result = userService.isFollowing(followerId, followingId)

        // then
        assertThat(result).isFalse()
    }

    // ──────────────────────────────────────────────
    // getFollowerCount() / getFollowingCount()
    // ──────────────────────────────────────────────

    @Test
    fun `should return follower count for given user`() {
        // given
        val userId = "user-B"

        `when`(followRepository.countByFollowingId(userId)).thenReturn(42L)

        // when
        val result = userService.getFollowerCount(userId)

        // then
        assertThat(result).isEqualTo(42L)
        verify(followRepository).countByFollowingId(userId)
    }

    @Test
    fun `should return zero follower count when no followers`() {
        // given
        val userId = "new-user"

        `when`(followRepository.countByFollowingId(userId)).thenReturn(0L)

        // when
        val result = userService.getFollowerCount(userId)

        // then
        assertThat(result).isZero()
    }

    @Test
    fun `should return following count for given user`() {
        // given
        val userId = "user-A"

        `when`(followRepository.countByFollowerId(userId)).thenReturn(10L)

        // when
        val result = userService.getFollowingCount(userId)

        // then
        assertThat(result).isEqualTo(10L)
        verify(followRepository).countByFollowerId(userId)
    }
}
```

